void init(FormRun callerForm )
{
    next init();

    //Assumes TargetControl is auto-declared, but we can get to it even if it's not
    MarkupTrans_MarkupCode1.registerOverrideMethod(methodStr(FormDataObject, lookup), formMethodStr(MarkupTrans, ETGmcrLookupSalesCodes));
}

public void ETGmcrLookupSalesCodes(FormControl _formControl)
{
    SysTableLookup          sysTableLookup;
    Query                   query = new Query();
    QueryBuildDataSource    qbds;


    sysTableLookup = SysTableLookup::newParameters(tableNum(MarkupTable),
                                                   _formControl);
    sysTableLookup.addLookupfield(fieldNum(MarkupTable, MarkupCode));
    sysTableLookup.addLookupfield(fieldNum(MarkupTable, Txt));

    qbds = query.addDataSource(tableNum(MarkupTable));
    qbds.addRange(fieldNum(MarkupTable, ModuleType)).value(enum2str(markupTrans.ModuleType));
    qbds.addRange(fieldNum(MarkupTable,ETGStdPosting)).value("@ETG_New:Yes");

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
